/* Test driver */
public class Main {
    public static void main(String[] args) {
        ATM atm = new ATM();
        Account a1 = new Account("A1", "Alice", 1000.00, "1234");
        Account a2 = new Account("A2", "Bob", 500.00, "5678");
        atm.registerAccount(a1);
        atm.registerAccount(a2);
        Card c = new Card("4111", "VISA", a1);
        atm.insertCard(c);
        atm.authenticate("1234");
        Receipt r = atm.transfer("A2", 300);
        if (r != null && Math.abs(a1.getBalance() - 700.0) < 0.01 && Math.abs(a2.getBalance() - 800.0) < 0.01) System.out.println("TRANSFER_OK");
        else System.out.println("TRANSFER_FAIL");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        ATM atm = new ATM();
        Account acc = new Account("A1", "Alice", 5000.00, "1234");
        atm.registerAccount(acc);
        Card c = new Card("4111", "VISA", acc);
        atm.insertCard(c);
        atm.authenticate("1234");
        Receipt r = atm.withdraw(2750);
        if (r == null) { System.out.println("CHAIN_FAIL"); return; }
        String s = r.toString();
        if (s.contains("2000") && s.contains("500") && Math.abs(acc.getBalance() - 2250.0) < 0.01) System.out.println("CHAIN_OK");
        else System.out.println("CHAIN_PARTIAL");
    }
}
